var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"메스해르츠 채널에서 전해드리는 핫이슈 시간!","JPN":"マスヘルツチャンネルでお送りするホットなニュースのお時間！","ENG":"Hot issues to you from the Masshertz channel!","TWN":"現在是梅斯赫茲頻道的熱點話題時間！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"현재 화제가 되고 있죠? 시니어를 암살하고 관리국의 수배를 받고 있는 그 인물!","JPN":"最近話題になっていますね？　シニアを暗殺して管理局から指名手配されているあの人物！","ENG":"It's what everyone is talking about right now. The Administration's most wanted for assassinating a Senior!","TWN":"如今被討論最多的，是這位暗殺了Senior並被管理局通緝的人物。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"유명 영화배우 스완 클레어의 민낯에 대해서 가장 잘 알고 있는 매니저를 모셨는데요.","JPN":"有名女優、スワン・クレアの素顔について一番よく知るマネージャーさんをお招きしました。","ENG":"We are currently with the famous actress, Swan Claire's manager who knows all her secrets.","TWN":"我們有幸請來了最了解著名電影演員史旺·克萊爾秘密的經紀人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"안녕하세요, 스완 클레어의 매니저분 맞으시죠?","JPN":"こんにちは、スワン・クレアのマネージャーさんですよね？","ENG":"Hello. You are Swan Claire's manager, correct?","TWN":"你好，你就是史旺·克萊爾的經紀人吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아, 그러니까요!","JPN":"だから、そうですって！","ENG":"Oh, come on!","TWN":"啊，沒錯！就是我！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"계속 말했잖아요! 저는 그 망할 년이 처음부터 그런 짓을 벌일지 알고 있었다니깐요?","JPN":"何度も言ってるじゃないですか！　私はあのクソ女があんなことをするって、最初からわかってたんです！","ENG":"I keep telling you! I knew that wretched bitch would do something like this from the second I met her!","TWN":"我早就說過了！我一開始就知道那個瘋女人會幹出這種事！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아하하. 흥분을 좀 가라앉히시고요.","JPN":"あはは。まあまあ少し落ち着いて。","ENG":"Ah hah hah. Why don't you calm down a bit.","TWN":"啊哈哈。請、請冷靜點吧……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"갑질이란 갑질은 다 하지, 시도 때도 없이 스케줄 변경하지, 약점 잡아서 협박하지……!","JPN":"偉そうにあれこれ言ってくるわ、しょっちゅうスケジュールを変更するわ、弱点を掴んで脅すわ……！","ENG":"She's bossy! Keeps changing her schedules on a whim! And even blackmailing others with their secrets...!","TWN":"太不講道理了！隨時隨地更改日程，還拼命揪住我的弱點勒索威脅……!"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아주 지긋지긋했다고요!","JPN":"もう、うんざりしてたんですよ！","ENG":"I'm sick of all of it!","TWN":"我真是受夠了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"음? 약점이라고요? 그건 어떤 약점이죠?","JPN":"えっ？　弱点？　それはどういう弱点なんですか？","ENG":"Hmm? Secret? What kind of secret?","TWN":"嗯？弱點？什麼樣的弱點？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아! 그, 그건!","JPN":"あっ！　そ、それは！","ENG":"Oh! Th-that's!","TWN":"啊！那、那個！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아하하, 이건 편집해 주시겠어요……?","JPN":"あはは、これはカットしてもらえますか……？","ENG":"Ah hah hah! Could you edit that out, please...?","TWN":"啊哈哈，這段能幫我剪掉嗎……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"……한편 수배 중인 스완이 제작한 드라마가 역대급 시청률을 기록하고 있는데요.","JPN":"……一方、指名手配中のスワンが製作したドラマが史上最高の視聴率を記録しています。","ENG":"...On a side note, the drama series produced by Swan Claire, who is currently wanted, is hitting record-breaking viewership ratings right now.","TWN":"……另一方面，通緝中的史旺製作的電視劇創下了歷史最高收視率。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그녀의 범죄가 드라마와 상당히 일치하며, 유례없는 극장형 범죄라는 점이 화제입니다.","JPN":"彼女の犯罪がドラマと相当一致しており、前例のない劇場型の犯罪であるというところが話題となっていますね。","ENG":"People are saying that her crimes and the series seem to overlap, and are calling it an unprecedented theatrical crime.","TWN":"她的犯罪與電視劇情節高度吻合，被稱為前所未有的戲劇性犯罪，引起了熱議。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"일각에서는 범죄자의 미화가 아니냐는 논란이 있는 가운데.","JPN":"一部では犯罪者を美化するのではないかという意見も出ている中、","ENG":"Among the controversy over whether it is a glorification of the criminal,","TWN":"也有人質疑這是否是在美化犯罪者，引發了爭議。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"감독과 스폰서는 각본가를 교체하여 드라마의 시즌2를 기획하고 있다고 발표하여…….","JPN":"監督とスポンサーは脚本家を再雇用し、ドラマのシーズン2を企画しているとの発表を……","ENG":"the director and sponsor have announced that they will be replacing the scriptwriter and are planning for a second season...","TWN":"導演和贊助商宣佈將更換編劇，計畫製作電視劇的第二季……"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이 천장… 이젠 낯설지가 않네.","JPN":"この天井……もう見飽きたな。","ENG":"This ceiling... It's so familiar now.","TWN":"病房的天花板啊……現在也不是那麼陌生了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님! 제가 밥 가져왔어요!","JPN":"先輩！　ご飯を持ってきました！","ENG":"Mina! I brought you your food!","TWN":"前輩，我給你帶了些吃的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘?","JPN":"ノエル？","ENG":"Noelle?","TWN":"洛艾兒？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"왜 네가 그걸 가져와? 너 다리에 깁스하고 있잖아. 의사가 특히 꼬리뼈를 조심하라던데.","JPN":"何であなたがそんなことするの？　脚にギプスをつけているのに。医者が特に尾骨には気を付けろって言ったよね。","ENG":"Why are you bringing that? You have a cast on your leg. Didn't the doctor tell you to be especially careful about your tailbone?","TWN":"為什麼是你給我帶來？你腿上打著石膏，而且醫生說要特別小心你的尾骨。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아요. 선배님이 싸인 해 주신 덕분에 금방 나았…","JPN":"大丈夫です。先輩がしてくれたサインのおかげですぐ治っ……","ENG":"It's all right. You signed my cast, so I'll be good in no ti–","TWN":"沒關係，多虧了你的親筆簽名，我很快就好……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄앗!!","JPN":"きゃあっ！！","ENG":"Kyaah!","TWN":"呀啊！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC_03"},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐아앙, 괜찮으세요?","JPN":"ふええん、大丈夫ですか？","ENG":"Waah... Are you okay?","TWN":"嗚嗚，你還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…정수리가 국 때문에 뜨거워.","JPN":"……頭が汁のせいで熱い。","ENG":"...You poured hot soup all over my head.","TWN":"……湯灑在我頭上了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"수, 수건 금방 가져올게요!","JPN":"タ、タオルを取ってきます！","ENG":"I-I'll be right back with some towels!","TWN":"我，我馬上去拿毛巾！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…다른 병실에도 다녀온 거지? 두 사람은 상태가 어때 보였어?","JPN":"……他の病室にも行ってきたんだね？　二人はどうだった？","ENG":"...You visited the others too, right? How are the other two doing?","TWN":"……你去過別的病房嗎？她們怎麼樣了？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"두 분은 링거 맞으면서 엄청 신기한 자세로 주무시고 계시더라구요.","JPN":"お二人は点滴を打ちながらすごく変わった体勢で寝てましたよ。","ENG":"Both are sleeping in weird positions while getting an IV.","TWN":"她們幾個正打著點滴，用非常神奇的姿勢睡覺呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"간호사분한테 들었는데, 사람이 너무 피곤할 땐 이틀을 넘게 잘 수도 있대요.","JPN":"看護師さんに聞きましたけど、人間って疲れすぎていると丸二日以上寝ることもあるらしいですよ。","ENG":"The nurse told me that people who are exhausted can sleep for over two days straight.","TWN":"我聽護士說，如果人筋疲力盡的話可以一直睡上兩天兩夜！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다행이네. 크게 다치지는 않은 것 같아서.","JPN":"よかったね。大きい怪我はないようで。","ENG":"That's good. I'm glad their injuries are minor.","TWN":"謝天謝地。看來傷勢不算太嚴重。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"거기 깍두기 좀 줄래? 오늘따라 젓가락질이 힘드네.","JPN":"そこの漬物取ってくれる？　今日はやけに箸を動かすのがきついね。","ENG":"Could you pass the radish kimchi? It's hard for me to use chopsticks right now.","TWN":"能給我夾一塊蘿蔔塊嗎？現在用起筷子來還是有些費勁呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네!","JPN":"はいっ！","ENG":"Okay!","TWN":"是！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아앙~ 하세요, 선배님!","JPN":"あ～んしてください、先輩！","ENG":"Say, \\"Ah,\\" Mina!","TWN":"張開嘴，前輩！啊～"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…아니다. 그냥 내가 먹을게.","JPN":"……いい。自分で食べる。","ENG":"...Never mind. I'll just eat it myself.","TWN":"……算了，還是我自己吃吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아! 오전에 힐데 대장님이 회사로 돌아오셨다면서요?","JPN":"あ！　午前にヒルデ隊長が会社に戻られたんですよね？","ENG":"Oh! I heard Commander Hilde came back to the company this morning!","TWN":"啊！我聽說希爾德隊長今早回公司了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응. 잠깐 우리 괜찮냐고 물어보더니 그대로 다시 떠났대.","JPN":"うん。大丈夫かって聞いただけですぐまた出たんだってさ。","ENG":"Yeah. She asked if we were all right then left again.","TWN":"是的，她詢問了一下我們的傷勢，然後又馬上離開了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"김하나 부장님 말로는 소대장이랑 키가 비슷한 꼬맹이가 하나 더 있었다는데…","JPN":"ナカシマ部長の話によると、チビ小隊長ぐらいの大きさのおこちゃまがもう一人いたようだけど……","ENG":"Manager Kim said that there was another kid around the same height as the commander with her...","TWN":"據千夜部長說，還有一個和小隊長差不多高的小不點……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"얼룩무늬꼬리가 엄청 부드러웠다나 뭐라나.","JPN":"しま模様の尻尾がとても柔らかかったとか何とか。","ENG":"She also said something about her striped tail being really soft and fluffy.","TWN":"還說什麼條紋尾巴摸起來特別柔軟。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꼬리요? 그런 게 달려있는 사람도 있나요?","JPN":"尻尾ですか？　そんなものが付いている人もいるんですか？","ENG":"Tail? There are people who have tails?","TWN":"尾巴？人類長著尾巴？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭐, 세상이 요지경인데 꼬리 하나쯤 달려있어도 이상할 건 없겠지.","JPN":"まぁ、こんな世の中だし、尻尾が付いている人がいるくらいおかしなことでもないよ。","ENG":"Well, with the world like this, there's nothing shocking about a person having a tail.","TWN":"如今這世道，就算人類長著尾巴也不足為奇了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"넌 괜찮아?","JPN":"あなたは大丈夫？","ENG":"Are you okay?","TWN":"你還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……啊？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아니 그냥… 평소보다 분위기가 좀 주눅 든 것 같아 보여서.","JPN":"いや、なんとなく……いつもより少し元気がない気がして。","ENG":"No, it's just... You seem a little down.","TWN":"沒什麼，只是你看起來……比平時有些無精打采。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"신경 쓰지 마.","JPN":"まぁ気にするな。","ENG":"Never mind.","TWN":"不，別在意這些。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님.","JPN":"先輩。","ENG":"Mina?","TWN":"前輩。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저…","JPN":"あの……","ENG":"Um...","TWN":"那個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"퇴원하고 나면 휴가 좀 다녀와도 될까요?","JPN":"退院したら休暇をとってもいいですか？","ENG":"Could I take some days off after I get discharged from the hospital?","TWN":"出院後，我可以休假嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"상관은 없지만… 어디로 가려고?","JPN":"いいけど……どこへ行くんだ？","ENG":"I don't see why not, but... where are you going?","TWN":"當然可以……不過，你想好去哪裡了麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헤, 본가에 좀 다녀오려고요.","JPN":"へへ、実家に行ってみようと思うんです。","ENG":"He he, I was thinking of visiting home.","TWN":"嘿嘿，我要回一趟老家。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그동안 여러가지 일들을 겪었더니, 갑자기 부모님 얼굴이 보고 싶어졌어요.","JPN":"今まで色んなことがあったから、急に両親の顔が見たくなって。","ENG":"After going through a lot of stuff, I suddenly wanted to see my parents.","TWN":"這段時間經歷了太多事，突然想去見見父母。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"얼마 뒤","JPN":"しばらくして","ENG":"A few days later","TWN":"不久之後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHIPMANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"……네?","JPN":"……えっ？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHIPMANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"이번에 출항하는 배에 스완 클레어가 타고 있다는 말씀인가요?","JPN":"今回出航する船に、スワン・クレアが乗っているってことですか？","ENG":"Are you talking about Swan Claire being on board the ship that's sailing out today?","TWN":"你是說這次出航的船上有史旺·克萊爾嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그렇다네. 관리국에서 비밀리에 입수한 정보지.","JPN":"そうだ。管理局で極秘で手に入れた情報だ。","ENG":"Yes. It's confidential information I got from the Administration.","TWN":"是的。這是管理局秘密獲取的資訊。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHIPMANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그렇지만 승선권 확인은 전부 마쳤는데요?","JPN":"で、ですが、乗船券の確認はもう終わってるはずですが。","ENG":"B-but we already checked all the boarding passes, didn't we?","TWN":"可、可是我們已經全部確認過登船證了啊？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"크흠, 이거 자네에게만 특별히 알려줘야겠군.","JPN":"コホン、これは君だけ特別に教えてやろう。","ENG":"Ahem. I'll let you in on a little secret.","TWN":"咳咳，這個只能特別告訴你了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"관리국에서 파악하고 있는 스완의 능력은 변신 능력이라네.","JPN":"管理局で把握しているスワンの能力は変身だ。","ENG":"The Administration confirmed that Swan's ability is transformation.","TWN":"管理局所掌握的史旺的能力是變身能力。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SHIPMANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"변신 능력이라고요?","JPN":"変身ですか？","ENG":"Transformation?","TWN":"變身能力嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그래, 그래서 지금껏 쉽게 잡을 수 없었던 거지. 보통의 방법으로는 식별할 수 없어.","JPN":"そう、だから今までそう何度も見逃してしまったんだ。普通の方法では識別できない。","ENG":"Correct. That's why we couldn't get her until now. There were no methods of identifying her.","TWN":"是的，所以到現在為止才一直很難抓住她。用普通的方法是無法識別的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"기밀 사항이니까 협조를 부탁하지.","JPN":"機密事項だから、よろしく頼む。","ENG":"It's all confidential, so I'd appreciate your cooperation.","TWN":"這是機密事項，請務必配合。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHIPMANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아, 알겠습니다. 그럼, 승객들에게 안내 방송을 하겠습니다.","JPN":"わ、わかりました。じゃあ、乗客に船内アナウンスをします。","ENG":"O-okay. Then, I'll make an announcement to our passengers.","TWN":"啊，明白了。那麼，我會向乘客們進行廣播。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"아니, 그건 안 돼. 혹여 스완이 눈치채면 곤란하니까.","JPN":"いや、それは駄目だ。スワンに気付かれたら困るからな。","ENG":"No, don't do that. It would make Swan catch wind of what's going on.","TWN":"不，那不行。如果讓她察覺到就麻煩了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"관리국 요원들이 검문을 진행하는 동안, 다른 이유를 대고 잠시 출항을 늦춰주게.","JPN":"管理局のエージェントが検問をしている間に、適当に理由をつけて出航を延期してくれ。","ENG":"While the Administration agents conduct an inspection, delay the departure by giving another reason.","TWN":"在管理局進行搜查期間，找個其他理由稍微延遲一下出航。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그거라면 충분해.","JPN":"それで十分だ。","ENG":"That'll be enough.","TWN":"那樣就足夠了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIPMANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"……자, 그럼.","JPN":"……さて。","ENG":"...All right, then.","TWN":"……好了，那就這樣吧。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"샤레이드로 밀입국할 생각인가?","JPN":"シャレードに密入国するつもりか？","ENG":"Are you thinking of smuggling into Charade?","TWN":"你打算偷渡到查雷德嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"음……?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……크윽!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳咳！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"못 본 사이에 미운 오리 새끼가 되어버렸군.","JPN":"見ない間、みにくいアヒルの子になってしまったな。","ENG":"You've become an ugly duckling since we last met.","TWN":"好久不見，竟然變成了醜小鴨。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"원래라면 좀 더 고상한 방법을 썼겠지. 스완 클레어.","JPN":"本来ならもっと優雅な方法を使っていたのだろう。スワン・クレア。","ENG":"You should've picked a more elegant method, Swan Claire.","TWN":"你應該用更高雅的方式的。史旺·克萊爾。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 당신들은 조금도 방심할 수 없는 존재네요.","JPN":"やはりあなたたちは少しも油断できませんね。","ENG":"Just as I thought. I shouldn't let my guard down against people like you.","TWN":"果然對付你們一點也不能掉以輕心。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"유명 배우라는 타이틀이 떨어지자마자, 제 목을 노리러 오시다니. 부지런도 하시네요.","JPN":"有名女優というタイトルがなくなったとたんに私の首を狙いに来るなんて。大変生真面目なこと。","ENG":"How diligent of you to come after me as soon as my title of being a famous actress is gone.","TWN":"一失去著名演員的頭銜，你們就來取我的性命。真是勤快啊。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네가 그걸 바란다면, 그렇게 해주는 게 인지상정일 테니까.","JPN":"お前がそれを望むというのなら、応えてやるのが世の情けだからな。","ENG":"If that is what you wish, then I'll be happy to oblige.","TWN":"如果這是你所希望的，那我只是順應人情世故而已。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"所以呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그 공들인 계획이 <color=#ffd34c>그 남자</color>에게 무너진 기분은 어떻지?","JPN":"この念入りの計画が<color=#ffd34c>あの男</color>に妨げられた気分はどうだ？","ENG":"How does it feel to have your elaborate plan be foiled by <color=#ffd34c>the man</color>?","TWN":"精心策劃的計畫被<color=#ffd34c>那個男人</color>破壞的感覺如何？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요?","JPN":"どうでしょう。","ENG":"Well.","TWN":"是麼。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어디 한 번 그 편리한 눈으로 꿰뚫어 보시죠? 제 기분이 어떨지.","JPN":"その便利な目で見抜いてみてください。私の気分を。","ENG":"Why don't you use that eye of yours to find out how I'm feeling?","TWN":"那就用你那雙方便的眼睛看看吧？猜猜我現在的心情如何？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"훗. 기억력이 나쁘군.","JPN":"ふっ。記憶力が悪いな。","ENG":"Pfft. Your memory isn't what it used to be?","TWN":"哼，記性真差。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"전에도 말하지 않았나? 이 눈이 모든 걸 보여주는 건 아니라고.","JPN":"前にも言ったはずだ。この目ですべてを見られるわけではないと。","ENG":"Didn't I say before? This eye doesn't show me everything.","TWN":"我之前不是說過嗎？這雙眼睛並不能看到所有東西。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"이를테면, 네가 겪은 과거는 보이지만, 그에 따른 네 생각과 감정까지는 알 수 없어.","JPN":"例えば、お前が経験した過去は見えるが、それによるお前の考えとか感情まではわからない。","ENG":"For example, I can see your past, but not the thoughts and emotions that come with it.","TWN":"比如，我能看到你經歷的過去，但無法知道你的想法和感受。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그래서 네 입으로 듣고 싶은 거야.","JPN":"だからお前の口から直接聞きたいんだ。","ENG":"So, I'd like you to tell me.","TWN":"所以我想親耳聽你說。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"<color=#ffd34c>너의 세계에 닥쳤던 시련을 이 세계에 재현하면서까지, 너는 뭘 증명하고 싶었던 거지?</color>","JPN":"<color=#ffd34c>お前の世界に訪れた試練をこの世界で再現してまで、お前は何を証明したかったんだ？</color>","ENG":"<color=#ffd34c>What were you trying to prove by reenacting the ordeals that befell your world in ours?</color>","TWN":"<color=#ffd34c>你到底想證明什麼，竟然要在這個世界重現你那個世界的試煉？</color>"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네가 추억하는 그 남자가 이 세계의 <color=#ffd34c>관리자</color>일지도 모른다고?","JPN":"お前が懐かしく思うあの男が、この世界の<color=#ffd34c>管理者</color>であるかもしれないということか？","ENG":"Because you think that the man in your memories might be <color=#ffd34c>the Administrator</color> in this one?","TWN":"就因為你懷念的那個男人很可能是這個世界的<color=#ffd34c>管理者</color>？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그걸 시험하기 위해서, 같은 조건과 상황을 만들어 낸건가?","JPN":"それを試すために、同じ条件と状況を作り上げたのか？","ENG":"Did you create the same conditions in this world to test that theory?","TWN":"為了驗證這一點，你製造了相同的條件和情況嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"하지만 결과는 어떻지?","JPN":"だが、結果はどうだ。","ENG":"What about the outcome?","TWN":"但結果又如何呢？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"네 고향이었던 그 빈약한 세계와 달리, 이 세계는…….","JPN":"お前の故郷だったあの貧弱な世界と違い、この世界は……","ENG":"This world isn't like your original impoverished world–","TWN":"和你原本的那個弱小世界不同，這個世界……"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"……큭!!","JPN":"……くっ！！","ENG":"...Kgh!!","TWN":"……咳！！"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오늘따라 유난히 혀가 기네요. 지수 씨답지 않아요.","JPN":"今日は話が長いですね。シノさんらしくありません。","ENG":"What's with all the talk today? This isn't like you.","TWN":"今天怎麼特別囉嗦，不像是你的風格啊，智秀。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"평소라면 혀보다 칼을 먼저 빼 들었을 텐데요?","JPN":"普段なら口より剣でかかってきたはずです。","ENG":"Don't you normally pull out your sword before you say anything?","TWN":"平時你不是應該先拔刀的嗎？"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"그걸 원한다면, 이 뒤부터는 검으로 묻지.","JPN":"そうしてほしいのなら、これからは剣で聞こう。","ENG":"If you want that, I'll ask my questions with my sword from now on.","TWN":"如果你想要那樣的話，接下來我就用劍來問話了。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_ON","text":{"KOREA":"어차피 시간은 충분할 테니까.","JPN":"どうせ時間は十分だ。","ENG":"We have enough time.","TWN":"反正時間應該是足夠的。"},"stage":{"bg":"DOCK_CLOUDY","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};